		self.children = [None]*26

class Trie:
	def __init__(self):
		self.root = TrieNode()

	def insert(self, word):
		node = self.root
		for c in word:
			if not node.children[ord(c)-97]:
				node.children[ord(c)-97] = TrieNode()
			node = node.children[ord(c)-97]
			if not word: 
					node.endOfWord = True;

class Solution:
	def solve(self, trie, query):
		node = trie.root
		count = 0
		for c in query:
			if node.children.get(ord(c)-97):
				count += 1
				if node.children[ord(c)-97].endOfWord:
					return count
				node = node.children[ord(c)-97]
		return count

def main():
	trie = Trie()
	trie.insert('apple')
	print(solve(trie, 'apple'))

